import{_ as t,o as a,c as s,a2 as i}from"./chunks/framework.BKG_UbFK.js";const u=JSON.parse('{"title":"Configuration","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/configuration.md","filePath":"en/guide/configuration.md"}'),d={name:"en/guide/configuration.md"};function o(n,e,r,c,l,p){return a(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h1><p>Clearance ships with sensible defaults, so it works out of the box after <a href="/clearance-docs/en/guide/installation.html">installation</a>. Publish the config file when you need to customize the route prefix, middleware, contextual models, or any other setting.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vendor:publish</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tag=clearance-config</span></span></code></pre></div><p>This publishes <code>config/clearance.php</code>.</p><h2 id="configuration-reference" tabindex="-1">Configuration reference <a class="header-anchor" href="#configuration-reference" aria-label="Permalink to &quot;Configuration reference&quot;">​</a></h2><p>This is the definitive reference for every key in <code>config/clearance.php</code>. Other pages in these docs link back here instead of repeating the table.</p><table tabindex="0"><thead><tr><th>Key</th><th>Default</th><th>Purpose</th></tr></thead><tbody><tr><td><code>route_prefix</code></td><td><code>&#39;clearance&#39;</code></td><td>URI prefix for all panel routes.</td></tr><tr><td><code>middleware</code></td><td><code>[&#39;web&#39;, &#39;auth&#39;]</code></td><td>Applied to all panel routes before <code>clearance.access</code>.</td></tr><tr><td><code>access_permission</code></td><td><code>&#39;clearance-access&#39;</code></td><td>Permission checked by the access middleware.</td></tr><tr><td><code>user_model</code></td><td><code>null</code></td><td>Defaults to <code>auth.providers.users.model</code>.</td></tr><tr><td><code>modules.users</code></td><td><code>false</code></td><td>Master switch for the Users module (routes + Livewire components).</td></tr><tr><td><code>contextual_models</code></td><td><code>[]</code></td><td><code>FQCN =&gt; [&#39;label&#39;, &#39;icon&#39;, &#39;label_attribute&#39;, &#39;searchable&#39;]</code> - models that can act as role-binding contexts.</td></tr><tr><td><code>enforce_naming_convention</code></td><td><code>true</code></td><td>Enforce <code>group-action</code> permission naming.</td></tr><tr><td><code>naming_separator</code></td><td><code>&#39;-&#39;</code></td><td>Separator character - <code>&#39;-&#39;</code> or <code>&#39;_&#39;</code> only.</td></tr><tr><td><code>guards</code></td><td><code>[]</code></td><td>Override auto-detected guards from <code>config/auth.php</code>. Empty = auto-detect all.</td></tr><tr><td><code>allowed_guard_drivers</code></td><td><code>[&#39;session&#39;, &#39;token&#39;, &#39;jwt&#39;, &#39;passport&#39;, &#39;sanctum&#39;]</code></td><td>Drivers accepted when injecting DB guards into <code>auth.guards</code>.</td></tr><tr><td><code>layout</code></td><td><code>null</code></td><td>Blade layout for full-page components. <code>null</code> = host app&#39;s default (<code>config(&#39;livewire.layout&#39;)</code>).</td></tr><tr><td><code>auto_assign_default_role</code></td><td><code>false</code></td><td>Auto-assign the Settings-configured default role on <code>Registered</code> event.</td></tr><tr><td><code>super_admin_gate_bypass</code></td><td><code>false</code></td><td>Opt-in: <code>super_admin</code> bypasses all Gate checks application-wide.</td></tr><tr><td><code>ui.flux_pro</code></td><td><code>null</code></td><td><code>null</code> = auto-detect via <code>Flux::pro()</code>.</td></tr></tbody></table><h2 id="permission-naming-convention" tabindex="-1">Permission naming convention <a class="header-anchor" href="#permission-naming-convention" aria-label="Permalink to &quot;Permission naming convention&quot;">​</a></h2><p>Permissions must follow the <code>group-action</code> format:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>orders-create       correct</span></span>
<span class="line"><span>orders-read         correct</span></span>
<span class="line"><span>store-orders-delete correct</span></span>
<span class="line"><span></span></span>
<span class="line"><span>create              wrong (bare action, no group)</span></span>
<span class="line"><span>orders.create       wrong (dot separator)</span></span>
<span class="line"><span>Orders-Create       wrong (camelCase)</span></span></code></pre></div><p>Disable enforcement per environment with <code>enforce_naming_convention</code>:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;enforce_naming_convention&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> false</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">Separator is validated at boot</p><p>The <code>naming_separator</code> value is the only piece of this config that reaches a raw SQL fragment (grouping/sorting permissions), so only <code>-</code> or <code>_</code> are accepted.</p></div><h2 id="customizing-middleware" tabindex="-1">Customizing middleware <a class="header-anchor" href="#customizing-middleware" aria-label="Permalink to &quot;Customizing middleware&quot;">​</a></h2><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// config/clearance.php</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;middleware&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;web&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;auth&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;verified&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span></code></pre></div><p>Route names stay stable regardless of prefix or middleware changes - see the <a href="/clearance-docs/en/guide/quick-start.html">Quick Start</a> for the full routes table.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/clearance-docs/en/guide/quick-start.html">Quick Start</a> - mounting the panel with these settings applied</li><li><a href="/clearance-docs/en/guide/publishing.html">Publishing assets</a> - publishing translations and understanding the <code>layout</code> key</li><li><a href="/clearance-docs/en/features/guards.html">Guards</a> - how <code>guards</code> and <code>allowed_guard_drivers</code> are used</li><li><a href="/clearance-docs/en/features/super-admin.html">Super Admin</a> - how <code>super_admin_gate_bypass</code> works</li></ul>`,18)])])}const g=t(d,[["render",o]]);export{u as __pageData,g as default};
